<script>document.addEventListener('DOMContentLoaded',function(){document.querySelectorAll('[data-unit-form]').forEach(function(form){var summary=form.querySelector('[data-validation-summary]');function showErrors(errors){summary.style.display=errors.length?'block':'none';summary.innerHTML=errors.map(function(e){return '<div>'+e+'</div>';}).join('');}form.addEventListener('submit',function(event){var errors=[];var nameAr=form.querySelector('[name="name_ar"]');var code=form.querySelector('[name="code"]');if(!nameAr.value.trim())errors.push('الاسم العربي مطلوب ولا يمكن تركه فارغاً.');if(!code.value.trim())errors.push('كود الوحدة مطلوب ولا يمكن تركه فارغاً.');if(errors.length){event.preventDefault();showErrors(errors);window.scrollTo({top:form.offsetTop-20,behavior:'smooth'});}});});});</script>
